if($_SERVER["REQUEST_METHOD"]=="POST"){ $name=mysqli_real_escape_string($conn,$_POST["name"]);$email=mysqli_real_escape_string($conn,$_POST["email"]);$password=mysqli_real_escape_string($conn,$_POST["password"]);$role=mysqli_real_escape_string($conn,$_POST["role"]); $add=isset($_POST["can_add_stock"])?1:0;$edit=isset($_POST["can_edit_stock"])?1:0;$del=isset($_POST["can_delete_stock"])?1:0;$reports=isset($_POST["can_view_reports"])?1:0;$staff=isset($_POST["can_manage_staff"])?1:0; if(mysqli_query($conn,"INSERT INTO users(name,email,password,role,can_add_stock,can_edit_stock,can_delete_stock,can_view_reports,can_manage_staff) VALUES('$name','$email','$password','$role',$add,$edit,$del,$reports,$staff)")){$msg="Staff account created successfully.";}else{$msg="Could not create staff account. Email may already exist.";} }
$users=mysqli_query($conn,"SELECT * FROM users ORDER BY role ASC");
?><!DOCTYPE html><html><head><title>Staff Access</title><link rel="stylesheet" href="assets/style.css"></head><body><div class="layout"><?php include "includes/sidebar.php"; ?><main class="main"><div class="page-title"><h1>Staff Access Management</h1><p>Only admin can create or disable staff accounts</p></div><div class="card"><h2>Create Authorized Staff Account</h2><p class="note">Public account creation is disabled. New users can only be added from this admin panel.</p><?php if($msg) echo "<p style='color:green'>$msg</p><br>"; ?><form method="POST" class="form-grid"><input name="name" placeholder="Staff full name" required><input type="email" name="email" placeholder="Email address" required><input name="password" placeholder="Temporary password" required><select name="role"><option>Manager</option><option>Staff</option><option>Viewer</option><option>Admin</option></select><label><input type="checkbox" name="can_add_stock" style="width:auto"> Can add stock</label><label><input type="checkbox" name="can_edit_stock" style="width:auto"> Can edit stock</label><label><input type="checkbox" name="can_delete_stock" style="width:auto"> Can delete stock</label><label><input type="checkbox" name="can_view_reports" style="width:auto"> Can view reports</label><label><input type="checkbox" name="can_manage_staff" style="width:auto"> Can manage staff</label><button>Create Staff Account</button></form></div><br><div class="card table-wrap"><h2>Current Users</h2><br><table><tr><th>Name</th><th>Email</th><th>Role</th><th>Permissions</th><th>Status</th><th>Action</th></tr><?php while($u=mysqli_fetch_assoc($users)){ ?><tr><td><?= $u["name"] ?></td><td><?= $u["email"] ?></td><td><?= $u["role"] ?></td><td>Add: <?= $u["can_add_stock"] ?> | Edit: <?= $u["can_edit_stock"] ?> | Delete: <?= $u["can_delete_stock"] ?> | Reports: <?= $u["can_view_reports"] ?> | Staff: <?= $u["can_manage_staff"] ?></td><td><?= $u["status"] ?></td><td><?php if($u["status"]=="Active"){ ?><a class="btn btn-danger" href="?disable=<?= $u["id"] ?>">Disable</a><?php } else { ?><a class="btn btn-light" href="?enable=<?= $u["id"] ?>">Enable</a><?php } ?></td></tr><?php } ?></table></div></main></div></body></html>